$ldap_size_limit = 100;

answer.programlisting:
#!/usr/bin/env bash

set -euo pipefail

readonly WP_PASS_FILE=".ldap_wp-proxy_pass"
readonly WP_CONF_DIR="/etc/white-pages"
readonly WP_LOCAL_CONF_FILE="${WP_CONF_DIR}/config.inc.local.php"
readonly WP_PASS_PATH="${WP_CONF_DIR}/${WP_PASS_FILE}"

echo "=== 1. Copy wp-proxy password ==="
if [[ ! -f "${HOME}/${WP_PASS_FILE}" ]]; then
	echo "Error: Password file '${WP_PASS_FILE}' not found."
	exit 1
fi

sudo install -m 400 "${HOME}/${WP_PASS_FILE}" "${WP_CONF_DIR}/${WP_PASS_FILE}"
sudo chown www-data:www-data "${WP_CONF_DIR}/${WP_PASS_FILE}"

echo "=== 2. Create White Pages local configuration file ==="

# shellcheck disable=SC2250
cat <<'EOF' |
<?php
$ldap_url          = "ldaps://ldap-srvr.lab.local:636";
$ldap_starttls     = false;
$ldap_binddn       = "uid=wp-proxy,ou=users,dc=lab,dc=local";
$ldap_bindpw       = trim(file_get_contents('__WP_PASS_PATH__'));
$ldap_base         = "dc=lab,dc=local";
$ldap_user_base    = "ou=users,".$ldap_base;
$ldap_user_filter  = "(objectClass=inetOrgPerson)";
$ldap_login_attribute = "uid";
$ldap_login_filter = "(&$ldap_user_filter($ldap_login_attribute={login}))";
$ldap_scope        = "sub";
$ldap_group_base   = "ou=groups,".$ldap_base;
$ldap_group_filter = "(|(objectClass=groupOfNames)(objectClass=groupOfUniqueNames)(objectClass=posixGroup))";
$ldap_size_limit   = 100;
EOF
	sed "s|__WP_PASS_PATH__|${WP_PASS_PATH}|g" | sudo tee "${WP_LOCAL_CONF_FILE}" >/dev/null

echo "=== 3. Set permissions for the local configuration file ==="
sudo chown www-data:www-data "${WP_LOCAL_CONF_FILE}"
sudo chmod 600 "${WP_LOCAL_CONF_FILE}"

echo "=== 4. Test Apache configuration ==="
sudo apache2ctl configtest

echo "=== 5. Reload Apache configuration ==="
sudo systemctl reload apache2

echo "================================================================="
echo " Success: White Pages has been configured to use the 'wp-proxy' service account."
echo " Local configuration file: ${WP_LOCAL_CONF_FILE}"
echo "================================================================="

#!/usr/bin/env bash
set -euo pipefail
readonly DOMAIN="lab.local" readonly BASE_DN="dc=${DOMAIN%%.*},dc=${DOMAIN#*.}" readonly USERS_OU="ou=users,${BASE_DN}" readonly LDAP_URI="ldap://ldap-srvr.lab.local" readonly ADMIN_DN="cn=admin,${BASE_DN}" readonly ADMIN_PASS_FILE="${HOME}/.ldap_admin_pass"
# LDAP common options readonly LDAP_OPTS=(-ZZ -H "${LDAP_URI}" -D "${ADMIN_DN}" -y "${ADMIN_PASS_FILE}")
# --- Functions --- die() { echo "Error: $*" >&2 exit 1 }
usage() { cat <<EOF Usage: $(basename "$0") -a|--add USER JPEG_FILE | -d|--delete USER EOF }
check_user_exists() { ldapsearch "${LDAP_OPTS[@]}" -LLL -b "${USERS_OU}" "(uid=$1)" dn | grep -q '^dn:' || die "User $1 not found." }
validate_jpeg() { [[ -f $1 && -s $1 ]] || die "Image missing or empty: $1" identify -format '%m' "$1" 2>/dev/null | grep -qi '^JPEG$' || die "$1 is not a valid JPEG." }
# --- Main --- main() { local action="" user="" jpeg_file="" local opts opts=$(getopt -o ad -l add,delete -- "$@") || { usage exit 1 } eval set -- "${opts}"
while true; do case "$1" in -a | --add) action="add"; shift ;; -d | --delete) action="delete"; shift ;; --) shift; break ;; *) usage; exit 1 ;; esac done
user="${1-}" jpeg_file="${2-}"
[[ -n ${action} && -n ${user} ]] || { usage exit 1 } [[ ${action} == "add" && -z ${jpeg_file} ]] && die "Add requires a JPEG file."
check_user_exists "${user}"
# LDIF file creation local ldif ldif=$(mktemp) trap 'rm -f "${ldif:-}"' EXIT
echo "dn: uid=${user},${USERS_OU}" >"${ldif}" echo "changetype: modify" >>"${ldif}"
if [[ ${action} == "add" ]]; then local jpeg_path validate_jpeg "${jpeg_file}" jpeg_path=$(realpath -- "${jpeg_file}") || die "Unable to resolve image path: ${jpeg_file}" echo "replace: jpegPhoto" >>"${ldif}" echo "jpegPhoto:< file://${jpeg_path}" >>"${ldif}" else echo "delete: jpegPhoto" >>"${ldif}" fi
echo "=== Applying LDAP modification ===" ldapmodify "${LDAP_OPTS[@]}" -f "${ldif}" echo "Success: Photo ${action}ed for ${user}." }
main "$@"

listitem.para:
La documentation officielle : &url.openldap.admin-guide;
        constitue le point d'entrée essentiel pour la mise en œuvre du service
        LDAP.
